import React, { useState } from 'react';
import { useData } from '../../context/DataContext';
import { useAuth } from '../../context/AuthContext';

// --- HELPER FUNCTIONS ---
const isSameDay = (d1, d2) => d1.toDateString() === d2.toDateString();
const isSameMonth = (d1, d2) => d1.getMonth() === d2.getMonth() && d1.getFullYear() === d2.getFullYear();
const isSameWeek = (d1, d2) => {
    const start = new Date(d2);
    start.setHours(0,0,0,0);
    start.setDate(start.getDate() - start.getDay() + 1); 
    const end = new Date(start);
    end.setDate(end.getDate() + 6);
    return d1 >= start && d1 <= end;
};

// --- ICONS ---
const Icons = {
    Task: () => (<svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="1.5"><path strokeLinecap="round" strokeLinejoin="round" d="M9 12h3.75M9 15h3.75M9 18h3.75m3 .75H18a2.25 2.25 0 002.25-2.25V6.108c0-1.135-.845-2.098-1.976-2.192a48.424 48.424 0 00-1.123-.08m-5.801 0c-.065.21-.1.433-.1.664 0 .414.336.75.75.75h4.5a.75.75 0 00.75-.75 2.25 2.25 0 00-.1-.664m-5.8 0A2.251 2.251 0 0113.5 2.25H15c1.012 0 1.867.668 2.15 1.586m-5.8 0c-.376.023-.75.05-1.124.08C9.095 4.01 8.25 4.973 8.25 6.108V8.25m0 0H4.875c-.621 0-1.125.504-1.125 1.125v11.25c0 .621.504 1.125 1.125 1.125h9.75c.621 0 1.125-.504 1.125-1.125V9.375c0-.621-.504-1.125-1.125-1.125H8.25zM6.75 12h.008v.008H6.75V12zm0 3h.008v.008H6.75V15zm0 3h.008v.008H6.75V18z" /></svg>),
    Schedule: () => (<svg width="24" height="24" fill="none" viewBox="0 0 24 24" stroke="#003366" strokeWidth="1.5"><path strokeLinecap="round" strokeLinejoin="round" d="M6.75 3v2.25M17.25 3v2.25M3 18.75V7.5a2.25 2.25 0 012.25-2.25h13.5A2.25 2.25 0 0121 7.5v11.25m-18 0A2.25 2.25 0 005.25 21h13.5A2.25 2.25 0 0021 18.75m-18 0v-7.5A2.25 2.25 0 015.25 9h13.5A2.25 2.25 0 0121 11.25v7.5" /></svg>),
    ArrowRight: () => (<svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2"><path strokeLinecap="round" strokeLinejoin="round" d="M13.5 4.5L21 12m0 0l-7.5 7.5M21 12H3" /></svg>),
    Back: () => (<svg width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth="2"><path strokeLinecap="round" strokeLinejoin="round" d="M10.5 19.5L3 12m0 0l7.5-7.5M3 12h18" /></svg>)
};

const TaskManager = () => {
  const { user } = useAuth();
  const { tasks, addTask, deleteTask, updateTask, staffList, disciplineTypes, schedules, addSchedule, deleteSchedule, updateSchedule } = useData();
  
  const activeDisciplines = disciplineTypes.filter(d => d.status === 'Active');
  
  // --- PHÂN QUYỀN ---
  const isScheduler = user?.role === 'scheduler';
  const isApprover = ['chief', 'reg', 'op'].includes(user?.role);

  // --- THẺ CON (SUB-TABS CHO ADMIN) ---
  const [activeView, setActiveView] = useState('overview'); // 'overview', 'create_task', 'create_schedule', 'manage_tasks', 'manage_schedules'

  const daysOfWeek = [
      { key: 'Mon', label: 'T2', val: 1 }, { key: 'Tue', label: 'T3', val: 2 }, { key: 'Wed', label: 'T4', val: 3 },
      { key: 'Thu', label: 'T5', val: 4 }, { key: 'Fri', label: 'T6', val: 5 }, { key: 'Sat', label: 'T7', val: 6 },
      { key: 'Sun', label: 'CN', val: 0 }
  ];

  // ==========================================
  // STATE & LOGIC CHO: MỤC 1 (GIAO NHIỆM VỤ)
  // ==========================================
  const [taskForm, setTaskForm] = useState({ 
      title: '', assigneeId: '', description: '', startTime: '', endTime: '', 
      assignedRole: 'ST', paymentAmount: '', disciplineId: ''
  });

  const handleCreateTask = (e) => {
      e.preventDefault();
      if (!taskForm.title || !taskForm.assigneeId || !taskForm.endTime) return alert("Vui lòng điền đủ thông tin!");
      const staff = staffList.find(s => s.id === taskForm.assigneeId);
      const disc = activeDisciplines.find(d => d.id === taskForm.disciplineId);
      
      addTask({ 
          ...taskForm, 
          assigneeName: staff ? staff.name : 'Unknown',
          disciplineName: disc ? disc.name : 'Chưa quy định',
          paymentType: taskForm.paymentAmount ? `${Number(taskForm.paymentAmount).toLocaleString()} VNĐ` : '0 VNĐ',
          deadline: taskForm.endTime,
          fromScheduleId: null
      });
      alert("Đã giao việc thành công!");
      setTaskForm({ title: '', assigneeId: '', description: '', startTime: '', endTime: '', assignedRole: 'ST', paymentAmount: '', disciplineId: '' });
  };

  // ==========================================
  // STATE & LOGIC CHO: MỤC 2 (LÊN LỊCH ĐỊNH KỲ)
  // ==========================================
  const [scheduleForm, setScheduleForm] = useState({ 
      title: '', assigneeId: '', description: '', startTime: '', endTime: '', assignedRole: 'ST' 
  });
  const [scheduleConfig, setScheduleConfig] = useState({ repeatWeeks: 1, days: [] });
  
  const handleDayToggle = (dayKey) => {
      setScheduleConfig(prev => {
          const exists = prev.days.includes(dayKey);
          return { ...prev, days: exists ? prev.days.filter(d => d !== dayKey) : [...prev.days, dayKey] };
      });
  };

  const generateTasksFromSchedule = (scheduleData, schedId) => {
      const { startTime, endTime, repeatWeeks, repeatDays } = scheduleData;
      const startObj = new Date(startTime);
      const endObj = new Date(endTime);
      const duration = endObj - startObj;
      const targetDayVals = daysOfWeek.filter(d => repeatDays.includes(d.key)).map(d => d.val);

      for (let w = 0; w < repeatWeeks; w++) {
          for (let d = 0; d < 7; d++) {
              const currentCheckDate = new Date(startObj);
              currentCheckDate.setDate(startObj.getDate() + (w * 7) + d);

              if (targetDayVals.includes(currentCheckDate.getDay())) {
                  const taskStart = new Date(currentCheckDate);
                  const taskEnd = new Date(taskStart.getTime() + duration);

                  addTask({
                      title: scheduleData.title,
                      assigneeId: scheduleData.assigneeId,
                      assigneeName: scheduleData.assigneeName,
                      description: scheduleData.description,
                      assignedRole: scheduleData.assignedRole,
                      startTime: taskStart.toISOString(),
                      endTime: taskEnd.toISOString(),
                      paymentType: 'Theo lịch', 
                      disciplineId: '', 
                      disciplineName: '',
                      deadline: taskEnd.toISOString(),
                      fromScheduleId: schedId,
                      generatedDate: new Date().toISOString()
                  });
              }
          }
      }
  };

  const handleCreateSchedule = (e) => {
      e.preventDefault();
      if (!scheduleForm.title || !scheduleForm.assigneeId || !scheduleForm.endTime) return alert("Vui lòng điền đủ thông tin!");
      if (scheduleConfig.days.length === 0) return alert("Vui lòng chọn ít nhất một ngày trong tuần!");
      
      const staff = staffList.find(s => s.id === scheduleForm.assigneeId);
      const scheduleData = {
          ...scheduleForm,
          assigneeName: staff ? staff.name : 'Unknown',
          repeatWeeks: Number(scheduleConfig.repeatWeeks),
          repeatDays: scheduleConfig.days,
          createdBy: user.username
      };

      const savedId = addSchedule(scheduleData);
      generateTasksFromSchedule(scheduleData, savedId);
      alert(`Đã lên lịch và tạo tasks cho ${scheduleData.assigneeName}!`);
      setScheduleForm({ title: '', assigneeId: '', description: '', startTime: '', endTime: '', assignedRole: 'ST' });
      setScheduleConfig({ repeatWeeks: 1, days: [] });
  };

  // ==========================================
  // LOGIC SỬA TRỰC TIẾP LỊCH TRÌNH (MỤC 4)
  // ==========================================
  const [editingSchedule, setEditingSchedule] = useState(null);

  const handleSaveEditSchedule = (e) => {
      e.preventDefault();
      const staff = staffList.find(s => s.id === editingSchedule.assigneeId);
      
      // 1. Cập nhật Root Schedule
      const updatedData = { ...editingSchedule, assigneeName: staff?.name || 'Unknown' };
      updateSchedule(editingSchedule.id, updatedData);

      // 2. Cập nhật Hàng loạt các Tasks được sinh ra từ Lịch này
      const relatedTasks = tasks.filter(t => t.fromScheduleId === editingSchedule.id);
      
      const newStart = new Date(editingSchedule.startTime);
      const newEnd = new Date(editingSchedule.endTime);

      relatedTasks.forEach(t => {
          if (updateTask) {
              // Lấy ngày của Task cũ, ráp Giờ/Phút của Lịch mới vào (Đảm bảo không bị nhảy ngày)
              const tStart = new Date(t.startTime);
              tStart.setHours(newStart.getHours(), newStart.getMinutes());
              const tEnd = new Date(t.endTime);
              tEnd.setHours(newEnd.getHours(), newEnd.getMinutes());

              updateTask(t.id, {
                  ...t, // Giữ nguyên checkInTime, checkOutTime, progress, status
                  title: updatedData.title,
                  assigneeId: updatedData.assigneeId,
                  assigneeName: updatedData.assigneeName,
                  assignedRole: updatedData.assignedRole,
                  description: updatedData.description,
                  startTime: tStart.toISOString(),
                  endTime: tEnd.toISOString()
              });
          }
      });

      alert("Đã cập nhật lịch và áp dụng thay đổi cho tất cả các ca làm việc liên quan!");
      setEditingSchedule(null);
  };


  // ==========================================
  // STATE BỘ LỌC CÁC BẢNG (MỤC 3 & 4)
  // ==========================================
  // Lọc Mục 3 (Op Tasks)
  const [filterOpStaff, setFilterOpStaff] = useState('all');
  const [filterOpTime, setFilterOpTime] = useState('all');
  const opAdminTasks = tasks.filter(t => !t.fromScheduleId).filter(t => {
      const d = new Date(t.startTime);
      const now = new Date();
      const matchStaff = filterOpStaff === 'all' || t.assigneeId === filterOpStaff;
      let matchTime = true;
      if (filterOpTime === 'day') matchTime = isSameDay(d, now);
      if (filterOpTime === 'week') matchTime = isSameWeek(d, now);
      if (filterOpTime === 'month') matchTime = isSameMonth(d, now);
      return matchStaff && matchTime;
  });

  // Lọc Mục 4 (Schedules & Schedule Tasks)
  const [scheduleSearchTerm, setScheduleSearchTerm] = useState('');
  const [filterSchedTaskStaff, setFilterSchedTaskStaff] = useState('all');
  const [filterSchedTaskTime, setFilterSchedTaskTime] = useState('all');

  const searchedAdminSchedules = schedules.filter(s => {
      if (!scheduleSearchTerm.trim()) return true;
      const term = scheduleSearchTerm.toLowerCase();
      return (s.title && s.title.toLowerCase().includes(term)) || (s.assigneeName && s.assigneeName.toLowerCase().includes(term));
  });

  const scheduleTasks = tasks.filter(t => t.fromScheduleId).filter(t => {
      const d = new Date(t.startTime);
      const now = new Date();
      const matchStaff = filterSchedTaskStaff === 'all' || t.assigneeId === filterSchedTaskStaff;
      let matchTime = true;
      if (filterSchedTaskTime === 'day') matchTime = isSameDay(d, now);
      if (filterSchedTaskTime === 'week') matchTime = isSameWeek(d, now);
      if (filterSchedTaskTime === 'month') matchTime = isSameMonth(d, now);
      return matchStaff && matchTime;
  });

  const formatTaskTime = (start, end) => {
      const s = new Date(start);
      const e = new Date(end);
      return (
          <div>
              <div style={{fontWeight:'bold', fontSize:'0.85rem'}}>{s.toLocaleDateString('vi-VN')}</div>
              <div style={{fontSize:'0.8rem', color:'#6b7280'}}>{`${s.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})} - ${e.toLocaleTimeString([], {hour:'2-digit', minute:'2-digit'})}`}</div>
          </div>
      );
  };


  // ==========================================
  // RENDER VIEWS CHO ADMIN
  // ==========================================
  
  if (isScheduler) {
      // Giao diện tĩnh cho tài khoản SCHEDULER (Giữ nguyên logic cũ)
      return (
          <div style={{ paddingBottom: '20px' }}>
              <h2 style={{ color: '#003366', borderBottom: '2px solid #e5e7eb', paddingBottom: '15px', marginBottom: '20px', fontWeight: 'bold', fontSize: '1.5rem' }}>
                  LÊN LỊCH CÔNG TÁC (SCHEDULER)
              </h2>
              {/* Form Lên Lịch của Scheduler */}
              <div style={{ background: '#fff', padding: '20px', borderRadius: '8px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)', marginBottom: '25px', border: '1px solid #f0f0f0' }}>
                  <h4 style={{ margin: '0 0 15px 0', color: '#003366', fontWeight: '600' }}>Lên lịch công tác mới</h4>
                  <form onSubmit={handleCreateSchedule} style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '16px' }}>
                      <div style={{ gridColumn: '1 / -1' }}><label style={styles.label}>Tiêu đề công việc</label><input value={scheduleForm.title} onChange={e => setScheduleForm({...scheduleForm, title: e.target.value})} style={styles.input} required /></div>
                      <div><label style={styles.label}>Người thực hiện</label><select value={scheduleForm.assigneeId} onChange={e => setScheduleForm({...scheduleForm, assigneeId: e.target.value})} style={styles.select} required><option value="">-- Chọn nhân sự --</option>{staffList.map(s => <option key={s.id} value={s.id}>{s.name} ({s.role})</option>)}</select></div>
                      <div><label style={styles.label}>Vai trò thực hiện</label><select value={scheduleForm.assignedRole} onChange={e => setScheduleForm({...scheduleForm, assignedRole: e.target.value})} style={styles.select}>{['ST','TT','CCS','CCO','CCA','FFM','FFS','FFA'].map(r => <option key={r} value={r}>{r}</option>)}</select></div>
                      <div><label style={styles.label}>Bắt đầu (Giờ)</label><input type="datetime-local" value={scheduleForm.startTime} onChange={e => setScheduleForm({...scheduleForm, startTime: e.target.value})} style={styles.input} required /></div>
                      <div><label style={styles.label}>Kết thúc (Giờ)</label><input type="datetime-local" value={scheduleForm.endTime} onChange={e => setScheduleForm({...scheduleForm, endTime: e.target.value})} style={styles.input} required /></div>
                      
                      <div style={{ gridColumn: '1 / -1', background: '#f9fafb', padding: '15px', borderRadius: '8px', border: '1px solid #e5e7eb' }}>
                          <h5 style={{margin:'0 0 10px 0', fontSize:'0.9rem', color:'#003366'}}>Cấu hình lặp lại</h5>
                          <div style={{display:'flex', alignItems:'center', gap:'20px', flexWrap:'wrap'}}>
                              <div style={{display:'flex', flexDirection:'column'}}><label style={styles.label}>Số tuần lặp lại:</label><input type="number" min="1" max="52" value={scheduleConfig.repeatWeeks} onChange={e => setScheduleConfig({...scheduleConfig, repeatWeeks: e.target.value})} style={{...styles.input, width: '100px'}} /></div>
                              <div style={{display:'flex', flexDirection:'column'}}><label style={styles.label}>Chọn thứ trong tuần:</label>
                                  <div style={{display:'flex', gap:'8px', marginTop:'5px', flexWrap: 'wrap'}}>
                                      {daysOfWeek.map(d => (
                                          <div key={d.key} onClick={() => handleDayToggle(d.key)} style={{ width:'32px', height:'32px', borderRadius:'50%', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'0.8rem', cursor:'pointer', fontWeight:'bold', border: '1px solid #d1d5db', background: scheduleConfig.days.includes(d.key) ? '#003366' : 'white', color: scheduleConfig.days.includes(d.key) ? 'white' : '#6b7280'}}>{d.label}</div>
                                      ))}
                                  </div>
                              </div>
                          </div>
                      </div>
                      <div style={{ gridColumn: '1 / -1' }}><label style={styles.label}>Mô tả chi tiết</label><textarea value={scheduleForm.description} onChange={e => setScheduleForm({...scheduleForm, description: e.target.value})} style={{...styles.input, height: '80px'}} /></div>
                      <button type="submit" style={styles.btnSubmit}>Lưu lịch & Tạo Tasks</button>
                  </form>
              </div>
          </div>
      );
  }

  // CHẾ ĐỘ HIỂN THỊ CỦA ADMIN (OP/CHIEF/REG)
  return (
    <div style={{ paddingBottom: '40px' }}>
      <h2 style={{ color: '#003366', borderBottom: '2px solid #e5e7eb', paddingBottom: '15px', marginBottom: '20px', fontWeight: 'bold', fontSize: '1.5rem' }}>
          QUẢN LÝ NHIỆM VỤ - THIẾT LẬP LỊCH TRÌNH
      </h2>

      {/* DASHBOARD CHỌN THẺ */}
      {activeView === 'overview' && (
          <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '20px' }}>
              <div style={styles.menuCard}>
                  <div style={{display:'flex', alignItems:'center', gap:'12px', marginBottom:'15px'}}>
                      <div style={styles.iconBox}><Icons.Task /></div>
                      <h3 style={styles.cardTitle}>1. Giao nhiệm vụ (TASK+)</h3>
                  </div>
                  <div style={{color:'#6b7280', fontSize:'0.9rem', marginBottom:'20px'}}>Giao việc thủ công và thiết lập mức kỷ luật, chi trả trực tiếp.</div>
                  <button onClick={() => setActiveView('create_task')} style={styles.accessBtn}>Truy cập <Icons.ArrowRight /></button>
              </div>

              <div style={styles.menuCard}>
                  <div style={{display:'flex', alignItems:'center', gap:'12px', marginBottom:'15px'}}>
                      <div style={styles.iconBox}><Icons.Schedule /></div>
                      <h3 style={styles.cardTitle}>2. Lên lịch định kỳ</h3>
                  </div>
                  <div style={{color:'#6b7280', fontSize:'0.9rem', marginBottom:'20px'}}>Tạo lịch làm việc lặp lại theo tuần cho nhân sự.</div>
                  <button onClick={() => setActiveView('create_schedule')} style={styles.accessBtn}>Truy cập <Icons.ArrowRight /></button>
              </div>

              <div style={styles.menuCard}>
                  <div style={{display:'flex', alignItems:'center', gap:'12px', marginBottom:'15px'}}>
                      <div style={styles.iconBox}><Icons.Task /></div>
                      <h3 style={styles.cardTitle}>3. Quản lý nhiệm vụ (TASK+)</h3>
                  </div>
                  <div style={{color:'#6b7280', fontSize:'0.9rem', marginBottom:'20px'}}>Theo dõi tiến độ các việc làm thủ công đã giao.</div>
                  <button onClick={() => setActiveView('manage_tasks')} style={styles.accessBtn}>Truy cập <Icons.ArrowRight /></button>
              </div>

              <div style={styles.menuCard}>
                  <div style={{display:'flex', alignItems:'center', gap:'12px', marginBottom:'15px'}}>
                      <div style={styles.iconBox}><Icons.Schedule /></div>
                      <h3 style={styles.cardTitle}>4. Quản lý lịch / Ca làm</h3>
                  </div>
                  <div style={{color:'#6b7280', fontSize:'0.9rem', marginBottom:'20px'}}>Sửa lịch gốc và theo dõi ca làm việc từ Scheduler.</div>
                  <button onClick={() => setActiveView('manage_schedules')} style={styles.accessBtn}>Truy cập <Icons.ArrowRight /></button>
              </div>
          </div>
      )}

      {/* MỤC 1: FORM GIAO NHIỆM VỤ THỦ CÔNG */}
      {activeView === 'create_task' && (
          <div style={styles.viewContainer}>
              <div style={styles.viewHeader}>
                  <h4 style={styles.viewTitle}>1. Giao nhiệm vụ (TASK+) & Kỷ luật</h4>
                  <button onClick={() => setActiveView('overview')} style={styles.backBtn}><Icons.Back /> Ẩn</button>
              </div>
              <form onSubmit={handleCreateTask} style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '16px' }}>
                  <div style={{ gridColumn: '1 / -1' }}><label style={styles.label}>Tiêu đề công việc</label><input value={taskForm.title} onChange={e => setTaskForm({...taskForm, title: e.target.value})} style={styles.input} required /></div>
                  <div><label style={styles.label}>Người thực hiện</label><select value={taskForm.assigneeId} onChange={e => setTaskForm({...taskForm, assigneeId: e.target.value})} style={styles.select} required><option value="">-- Chọn nhân sự --</option>{staffList.map(s => <option key={s.id} value={s.id}>{s.name} ({s.role})</option>)}</select></div>
                  <div><label style={styles.label}>Vai trò thực hiện</label><select value={taskForm.assignedRole} onChange={e => setTaskForm({...taskForm, assignedRole: e.target.value})} style={styles.select}>{['ST','TT','CCS','CCO','CCA','FFM','FFS','FFA'].map(r => <option key={r} value={r}>{r}</option>)}</select></div>
                  <div><label style={styles.label}>Bắt đầu (Check-in)</label><input type="datetime-local" value={taskForm.startTime} onChange={e => setTaskForm({...taskForm, startTime: e.target.value})} style={styles.input} required /></div>
                  <div><label style={styles.label}>Hạn chót (Check-out)</label><input type="datetime-local" value={taskForm.endTime} onChange={e => setTaskForm({...taskForm, endTime: e.target.value})} style={styles.input} required /></div>
                  <div><label style={styles.label}>Mức tiền chi trả (VNĐ)</label><input type="number" placeholder="Nhập số tiền..." value={taskForm.paymentAmount} onChange={e => setTaskForm({...taskForm, paymentAmount: e.target.value})} style={styles.input} /></div>
                  <div><label style={styles.label}>Kỷ luật (nếu trễ)</label><select value={taskForm.disciplineId} onChange={e => setTaskForm({...taskForm, disciplineId: e.target.value})} style={{...styles.select, borderColor: 'red', color: '#b91c1c'}}><option value="">-- Chọn hình thức --</option>{activeDisciplines.map(d => <option key={d.id} value={d.id}>{d.name}</option>)}</select></div>
                  <div style={{ gridColumn: '1 / -1' }}><label style={styles.label}>Mô tả chi tiết</label><textarea value={taskForm.description} onChange={e => setTaskForm({...taskForm, description: e.target.value})} style={{...styles.input, height: '80px'}} /></div>
                  <button type="submit" style={styles.btnSubmit}>Giao việc</button>
              </form>
          </div>
      )}

      {/* MỤC 2: FORM LÊN LỊCH ĐỊNH KỲ */}
      {activeView === 'create_schedule' && (
          <div style={styles.viewContainer}>
              <div style={styles.viewHeader}>
                  <h4 style={styles.viewTitle}>2. Lên lịch công tác định kỳ</h4>
                  <button onClick={() => setActiveView('overview')} style={styles.backBtn}><Icons.Back /> Ẩn</button>
              </div>
              <form onSubmit={handleCreateSchedule} style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))', gap: '16px' }}>
                  <div style={{ gridColumn: '1 / -1' }}><label style={styles.label}>Tiêu đề công việc</label><input value={scheduleForm.title} onChange={e => setScheduleForm({...scheduleForm, title: e.target.value})} style={styles.input} required /></div>
                  <div><label style={styles.label}>Người thực hiện</label><select value={scheduleForm.assigneeId} onChange={e => setScheduleForm({...scheduleForm, assigneeId: e.target.value})} style={styles.select} required><option value="">-- Chọn nhân sự --</option>{staffList.map(s => <option key={s.id} value={s.id}>{s.name} ({s.role})</option>)}</select></div>
                  <div><label style={styles.label}>Vai trò thực hiện</label><select value={scheduleForm.assignedRole} onChange={e => setScheduleForm({...scheduleForm, assignedRole: e.target.value})} style={styles.select}>{['ST','TT','CCS','CCO','CCA','FFM','FFS','FFA'].map(r => <option key={r} value={r}>{r}</option>)}</select></div>
                  <div><label style={styles.label}>Bắt đầu (Giờ)</label><input type="datetime-local" value={scheduleForm.startTime} onChange={e => setScheduleForm({...scheduleForm, startTime: e.target.value})} style={styles.input} required /></div>
                  <div><label style={styles.label}>Kết thúc (Giờ)</label><input type="datetime-local" value={scheduleForm.endTime} onChange={e => setScheduleForm({...scheduleForm, endTime: e.target.value})} style={styles.input} required /></div>
                  
                  <div style={{ gridColumn: '1 / -1', background: '#f9fafb', padding: '15px', borderRadius: '8px', border: '1px solid #e5e7eb' }}>
                      <h5 style={{margin:'0 0 10px 0', fontSize:'0.9rem', color:'#003366'}}>Cấu hình lặp lại</h5>
                      <div style={{display:'flex', alignItems:'center', gap:'20px', flexWrap:'wrap'}}>
                          <div style={{display:'flex', flexDirection:'column'}}><label style={styles.label}>Số tuần lặp lại:</label><input type="number" min="1" max="52" value={scheduleConfig.repeatWeeks} onChange={e => setScheduleConfig({...scheduleConfig, repeatWeeks: e.target.value})} style={{...styles.input, width: '100px'}} /></div>
                          <div style={{display:'flex', flexDirection:'column'}}><label style={styles.label}>Chọn thứ trong tuần:</label>
                              <div style={{display:'flex', gap:'8px', marginTop:'5px', flexWrap: 'wrap'}}>
                                  {daysOfWeek.map(d => (
                                      <div key={d.key} onClick={() => handleDayToggle(d.key)} style={{ width:'32px', height:'32px', borderRadius:'50%', display:'flex', alignItems:'center', justifyContent:'center', fontSize:'0.8rem', cursor:'pointer', fontWeight:'bold', border: '1px solid #d1d5db', background: scheduleConfig.days.includes(d.key) ? '#003366' : 'white', color: scheduleConfig.days.includes(d.key) ? 'white' : '#6b7280'}}>{d.label}</div>
                                  ))}
                              </div>
                          </div>
                      </div>
                  </div>
                  <div style={{ gridColumn: '1 / -1' }}><label style={styles.label}>Mô tả chi tiết</label><textarea value={scheduleForm.description} onChange={e => setScheduleForm({...scheduleForm, description: e.target.value})} style={{...styles.input, height: '80px'}} /></div>
                  <button type="submit" style={styles.btnSubmit}>Lưu lịch & Tạo Tasks</button>
              </form>
          </div>
      )}

      {/* MỤC 3: QUẢN LÝ NHIỆM VỤ (TASK+) */}
      {activeView === 'manage_tasks' && (
          <div style={styles.viewContainer}>
              <div style={styles.viewHeader}>
                  <h4 style={styles.viewTitle}>3. Quản lý nhiệm vụ (TASK+)</h4>
                  <button onClick={() => setActiveView('overview')} style={styles.backBtn}><Icons.Back /> Ẩn</button>
              </div>
              <div style={{display:'flex', gap:'10px', flexWrap:'wrap', marginBottom:'15px'}}>
                  <select value={filterOpStaff} onChange={e => setFilterOpStaff(e.target.value)} style={styles.filterSelect}><option value="all">Tất cả nhân sự</option>{staffList.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}</select>
                  <select value={filterOpTime} onChange={e => setFilterOpTime(e.target.value)} style={styles.filterSelect}><option value="all">Tất cả thời gian</option><option value="day">Hôm nay</option><option value="week">Tuần này</option><option value="month">Tháng này</option></select>
              </div>
              <div style={{overflowX: 'auto'}}>
                  <table style={styles.table}>
                     <thead>
                        <tr style={styles.tableHeadRow}>
                          <th style={styles.thCell}>STT</th>
                          <th style={styles.thCell}>Nhiệm vụ</th>
                          <th style={styles.thCell}>Người làm</th>
                          <th style={styles.thCell}>Vai trò</th>
                          <th style={styles.thCell}>Mức chi trả</th>
                          <th style={styles.thCell}>Thời gian</th>
                          <th style={styles.thCell}>Tiến độ</th>
                          <th style={styles.thCell}>Xóa</th>
                        </tr>
                     </thead>
                     <tbody>
                        {opAdminTasks.map((t, index) => (
                          <tr key={t.id} style={{ borderBottom: '1px solid #f9f9f9' }}>
                             <td style={{padding:'12px', textAlign:'center', fontWeight:'bold', color:'#9ca3af'}}>{index + 1}</td>
                             <td style={{padding:'12px'}}><strong>{t.title}</strong><br/><span style={{fontSize:'0.75rem', color:'#dc2626'}}>{t.disciplineName || ''}</span></td>
                             <td style={{padding:'12px'}}>{t.assigneeName}</td>
                             <td style={{padding:'12px'}}>{t.assignedRole}</td>
                             <td style={{padding:'12px', color:'#059669', fontWeight:'bold'}}>{t.paymentType}</td>
                             <td style={{padding:'12px'}}>{formatTaskTime(t.startTime, t.endTime)}</td>
                             <td style={{padding:'12px'}}>{t.progress}%</td>
                             <td style={{padding:'12px'}}><button onClick={()=>handleDeleteTask(t.id)} style={{color:'red', border:'none', background:'none', cursor:'pointer'}}>Xóa</button></td>
                          </tr>
                        ))}
                        {opAdminTasks.length === 0 && <tr><td colSpan="8" style={{padding:'30px', textAlign:'center', color:'#9ca3af', fontStyle:'italic'}}>Không tìm thấy nhiệm vụ.</td></tr>}
                     </tbody>
                  </table>
              </div>
          </div>
      )}

      {/* MỤC 4: QUẢN LÝ LỊCH VÀ CA LÀM */}
      {activeView === 'manage_schedules' && (
          <div style={{ display: 'flex', flexDirection: 'column', gap: '25px' }}>
              
              {/* BẢNG LỊCH GỐC (CÓ EDIT) */}
              <div style={styles.viewContainer}>
                  <div style={styles.viewHeader}>
                      <h4 style={styles.viewTitle}>4.1 Danh sách lịch gốc định kỳ</h4>
                      <div style={{display:'flex', gap:'10px'}}>
                          <input type="text" placeholder="Tìm kiếm lịch gốc..." value={scheduleSearchTerm} onChange={(e) => setScheduleSearchTerm(e.target.value)} style={{...styles.input, width: '250px', marginTop: 0}} />
                          <button onClick={() => setActiveView('overview')} style={styles.backBtn}><Icons.Back /> Ẩn</button>
                      </div>
                  </div>

                  {editingSchedule && (
                      <div style={{background:'#f0fdf4', padding:'15px', borderRadius:'8px', border:'1px solid #bbf7d0', marginBottom:'15px'}}>
                          <h5 style={{margin:'0 0 10px 0', color:'#166534'}}>✏️ Sửa trực tiếp lịch trình (Áp dụng cho toàn bộ ca làm việc)</h5>
                          <form onSubmit={handleSaveEditSchedule} style={{display:'flex', gap:'10px', flexWrap:'wrap', alignItems:'flex-end'}}>
                              <div style={{flex:1, minWidth:'150px'}}><label style={styles.label}>Tiêu đề</label><input value={editingSchedule.title} onChange={e=>setEditingSchedule({...editingSchedule, title:e.target.value})} style={styles.input} required/></div>
                              <div style={{flex:1, minWidth:'150px'}}><label style={styles.label}>Người thực hiện</label><select value={editingSchedule.assigneeId} onChange={e=>setEditingSchedule({...editingSchedule, assigneeId:e.target.value})} style={styles.select}>{staffList.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}</select></div>
                              <div style={{width:'100px'}}><label style={styles.label}>Vai trò</label><select value={editingSchedule.assignedRole} onChange={e=>setEditingSchedule({...editingSchedule, assignedRole:e.target.value})} style={styles.select}>{['ST','TT','CCS','CCO','CCA','FFM','FFS','FFA'].map(r=><option key={r} value={r}>{r}</option>)}</select></div>
                              <div style={{flex:1, minWidth:'150px'}}><label style={styles.label}>Bắt đầu (Giờ)</label><input type="datetime-local" value={editingSchedule.startTime} onChange={e=>setEditingSchedule({...editingSchedule, startTime:e.target.value})} style={styles.input} required/></div>
                              <div style={{flex:1, minWidth:'150px'}}><label style={styles.label}>Kết thúc (Giờ)</label><input type="datetime-local" value={editingSchedule.endTime} onChange={e=>setEditingSchedule({...editingSchedule, endTime:e.target.value})} style={styles.input} required/></div>
                              <button type="submit" style={{...styles.btnSubmit, width:'auto', background:'#16a34a'}}>Lưu thay đổi</button>
                              <button type="button" onClick={()=>setEditingSchedule(null)} style={{...styles.btnSubmit, width:'auto', background:'#9ca3af'}}>Hủy</button>
                          </form>
                      </div>
                  )}

                  <div style={{overflowX: 'auto'}}>
                      <table style={styles.table}>
                        <thead>
                           <tr style={styles.tableHeadRow}>
                             <th style={styles.thCell}>STT</th>
                             <th style={styles.thCell}>Thông tin lịch trình</th>
                             <th style={styles.thCell}>Hành động</th>
                           </tr>
                        </thead>
                        <tbody>
                           {searchedAdminSchedules.map((s, index) => (
                             <tr key={s.id} style={{ borderBottom: '1px solid #f9f9f9' }}>
                                <td style={{padding:'12px', textAlign:'center', fontWeight:'bold', color:'#9ca3af', width:'50px'}}>{index + 1}</td>
                                <td style={{padding:'12px'}}>
                                    <strong>{s.title}</strong>
                                    {s.assigneeName && <div style={{fontSize:'0.8rem', color:'#6b7280'}}>Phụ trách: {s.assigneeName} ({s.assignedRole})</div>}
                                </td>
                                <td style={{padding:'12px'}}>
                                    <button onClick={()=>setEditingSchedule(s)} style={{color:'#003366', border:'none', background:'none', cursor:'pointer', marginRight:'10px', fontWeight:'600'}}>Sửa</button>
                                    <button onClick={()=>handleDeleteSchedule(s.id)} style={{color:'#dc2626', border:'none', background:'none', cursor:'pointer', fontWeight:'600'}}>Xóa</button>
                                </td>
                             </tr>
                           ))}
                        </tbody>
                      </table>
                  </div>
              </div>

              {/* BẢNG CA LÀM VIỆC ĐƯỢC TẠO RA TỪ LỊCH GỐC */}
              <div style={styles.viewContainer}>
                  <div style={styles.viewHeader}>
                      <h4 style={styles.viewTitle}>4.2 Danh sách ca làm việc (Phát sinh từ lịch)</h4>
                  </div>
                  <div style={{display:'flex', gap:'10px', flexWrap:'wrap', marginBottom:'15px'}}>
                      <select value={filterSchedTaskStaff} onChange={e => setFilterSchedTaskStaff(e.target.value)} style={styles.filterSelect}><option value="all">Tất cả nhân sự</option>{staffList.map(s => <option key={s.id} value={s.id}>{s.name}</option>)}</select>
                      <select value={filterSchedTaskTime} onChange={e => setFilterSchedTaskTime(e.target.value)} style={styles.filterSelect}><option value="all">Tất cả thời gian</option><option value="day">Hôm nay</option><option value="week">Tuần này</option><option value="month">Tháng này</option></select>
                  </div>
                  <div style={{overflowX: 'auto'}}>
                      <table style={styles.table}>
                         <thead>
                            <tr style={styles.tableHeadRow}>
                              <th style={styles.thCell}>STT</th>
                              <th style={styles.thCell}>Nhiệm vụ</th>
                              <th style={styles.thCell}>Người làm</th>
                              <th style={styles.thCell}>Vai trò</th>
                              <th style={styles.thCell}>Thời gian</th>
                              <th style={styles.thCell}>Tiến độ</th>
                              <th style={styles.thCell}>Xóa</th>
                            </tr>
                         </thead>
                         <tbody>
                            {scheduleTasks.map((t, index) => (
                              <tr key={t.id} style={{ borderBottom: '1px solid #f9f9f9' }}>
                                 <td style={{padding:'12px', textAlign:'center', fontWeight:'bold', color:'#9ca3af'}}>{index + 1}</td>
                                 <td style={{padding:'12px'}}><strong>{t.title}</strong></td>
                                 <td style={{padding:'12px'}}>{t.assigneeName}</td>
                                 <td style={{padding:'12px'}}>{t.assignedRole}</td>
                                 <td style={{padding:'12px'}}>{formatTaskTime(t.startTime, t.endTime)}</td>
                                 <td style={{padding:'12px'}}>{t.progress}%</td>
                                 <td style={{padding:'12px'}}><button onClick={()=>handleDeleteTask(t.id)} style={{color:'red', border:'none', background:'none', cursor:'pointer'}}>Xóa</button></td>
                              </tr>
                            ))}
                            {scheduleTasks.length === 0 && <tr><td colSpan="7" style={{padding:'30px', textAlign:'center', color:'#9ca3af', fontStyle:'italic'}}>Không tìm thấy ca làm việc.</td></tr>}
                         </tbody>
                      </table>
                  </div>
              </div>
          </div>
      )}
    </div>
  );
};

const styles = {
    viewContainer: { background: 'white', padding: '20px', borderRadius: '16px', boxShadow: '0 4px 6px -1px rgba(0,0,0,0.05)', border: '1px solid #e5e7eb', marginBottom: '25px' },
    viewHeader: { display:'flex', justifyContent:'space-between', alignItems:'center', flexWrap:'wrap', gap:'10px', marginBottom:'20px', borderBottom:'1px solid #f3f4f6', paddingBottom:'15px' },
    viewTitle: { margin: 0, fontSize: '1.2rem', color:'#003366' },
    table: { width: '100%', borderCollapse: 'collapse', fontSize: '0.9rem', minWidth: '600px' },
    tableHeadRow: { textAlign:'left', borderBottom: '1px solid #eee', background:'#f9fafb', color:'#6b7280' },
    thCell: { padding:'12px' },
    input: { width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #ccc', marginTop: '5px', boxSizing: 'border-box' },
    select: { width: '100%', padding: '10px', borderRadius: '8px', border: '1px solid #ccc', marginTop: '5px', background: 'white' },
    filterSelect: { padding: '6px 12px', borderRadius: '6px', border: '1px solid #d1d5db', outline: 'none', color: '#374151', cursor: 'pointer', background:'white' },
    label: { fontSize: '0.8rem', fontWeight: 'bold', color: '#555' },
    btnSubmit: { gridColumn: '1 / -1', padding: '12px', background: '#003366', color: 'white', border: 'none', borderRadius: '8px', fontWeight: 'bold', cursor: 'pointer' },
    menuCard: { background: 'white', borderRadius: '12px', padding: '20px', boxShadow: '0 4px 6px rgba(0,0,0,0.05)', border: '1px solid #e5e7eb', display: 'flex', flexDirection: 'column', justifyContent: 'space-between', minHeight: '160px' },
    iconBox: { width: '36px', height: '36px', background: '#e0f2fe', borderRadius: '8px', display: 'flex', alignItems: 'center', justifyContent: 'center', color: '#003366' },
    cardTitle: { margin: 0, fontSize: '1rem', fontWeight: '600', color: '#1f2937' },
    accessBtn: { marginTop: 'auto', background: '#003366', color: 'white', border: 'none', padding: '10px 16px', borderRadius: '8px', cursor: 'pointer', fontWeight: '600', display: 'flex', alignItems: 'center', justifyContent: 'center', gap: '8px', transition: 'background 0.2s' },
    backBtn: { background: '#fef2f2', color: '#ef4444', border: '1px solid #fecaca', padding: '6px 12px', borderRadius: '8px', cursor: 'pointer', fontWeight: '600', display: 'flex', alignItems: 'center', gap: '6px' }
};

export default TaskManager;
